# radar_scorer.py
# Computes a ring recommendation based on weighted evaluation criteria.

from dataclasses import dataclass

@dataclass
class RadarBlipScore:
    blip_name: str
    technical_readiness: float   # 0-1: benchmarks, stability, API maturity
    security_compliance: float   # 0-1: certifications, audit coverage
    operational_maturity: float  # 0-1: monitoring, runbooks, on-call support

    WEIGHTS = {"technical_readiness": 0.4, "security_compliance": 0.35, "operational_maturity": 0.25}

    @property
    def composite_score(self) -> float:
        return (
            self.technical_readiness * self.WEIGHTS["technical_readiness"]
            + self.security_compliance * self.WEIGHTS["security_compliance"]
            + self.operational_maturity * self.WEIGHTS["operational_maturity"]
        )

    @property
    def recommended_ring(self) -> str:
        s = self.composite_score
        if s >= 0.80:
            return "ADOPT"
        elif s >= 0.60:
            return "TRIAL"
        elif s >= 0.40:
            return "ASSESS"
        else:
            return "HOLD"

# Example evaluation
scores = [
    RadarBlipScore("GPT-4o", technical_readiness=0.92, security_compliance=0.88, operational_maturity=0.85),
    RadarBlipScore("LangGraph", technical_readiness=0.75, security_compliance=0.70, operational_maturity=0.55),
    RadarBlipScore("Experimental LLM", technical_readiness=0.45, security_compliance=0.30, operational_maturity=0.20),
]
for blip in scores:
    print(f"{blip.blip_name}: {blip.composite_score:.2f} → {blip.recommended_ring}")
# GPT-4o: 0.89 → ADOPT
# LangGraph: 0.67 → TRIAL
# Experimental LLM: 0.37 → HOLD

# radar_automation.py
# Automates blip status monitoring and drift alerts between quarterly reviews.

import datetime
from dataclasses import dataclass, field
from enum import Enum

class Ring(str, Enum):
    ADOPT = "ADOPT"
    TRIAL = "TRIAL"
    ASSESS = "ASSESS"
    HOLD = "HOLD"

@dataclass
class Blip:
    id: str
    name: str
    quadrant: str
    ring: Ring
    owner: str
    score: float  # composite 0-1
    last_reviewed: datetime.date
    review_cadence_days: int = 90

    @property
    def is_stale(self) -> bool:
        age = (datetime.date.today() - self.last_reviewed).days
        return age > self.review_cadence_days

    @property
    def score_ring(self) -> Ring:
        if self.score >= 0.80: return Ring.ADOPT
        if self.score >= 0.60: return Ring.TRIAL
        if self.score >= 0.40: return Ring.ASSESS
        return Ring.HOLD

    @property
    def has_ring_drift(self) -> bool:
        return self.ring != self.score_ring

@dataclass
class RadarMonitor:
    blips: list[Blip] = field(default_factory=list)

    def stale_blips(self) -> list[Blip]:
        return [b for b in self.blips if b.is_stale]

    def drifted_blips(self) -> list[Blip]:
        return [b for b in self.blips if b.has_ring_drift]

    def summary(self) -> dict:
        return {
            "total": len(self.blips),
            "stale": len(self.stale_blips()),
            "drifted": len(self.drifted_blips()),
            "by_ring": {r.value: sum(1 for b in self.blips if b.ring == r) for r in Ring},
        }

# Example usage
monitor = RadarMonitor(blips=[
    Blip("BLP-001", "GPT-4o", "models", Ring.ADOPT, "alice@co", 0.89,
         datetime.date(2025, 1, 15)),
    Blip("BLP-003", "LangGraph", "frameworks", Ring.TRIAL, "bob@co", 0.75,
         datetime.date(2025, 3, 1)),
])
print(monitor.summary())
for b in monitor.drifted_blips():
    print(f"DRIFT: {b.name} is {b.ring.value} but scores {b.score_ring.value}")
